import re

def detect_secrets_in_output(agent_output: str) -> list:
    patterns = [
        r'api[_-]?key\s*[=:]\s*["\']?([a-zA-Z0-9]{20,})',
        r'password\s*[=:]\s*["\']?([^\s"\']{8,})',
        r'([a-zA-Z0-9]{32,})\s*=\s*["\']?password',
        r'Bearer\s+([a-zA-Z0-9._-]{20,})'
    ]
    secrets = []
    for pattern in patterns:
        matches = re.finditer(pattern, agent_output, re.IGNORECASE)
        for match in matches:
            secrets.append({
                'pattern': pattern,
                'secret': match.group(1),
                'location': match.span()
            })
    return secrets

import os
import re

def detect_env_leaks(agent_output: str) -> list:
    sensitive_vars = ['API_KEY', 'PASSWORD', 'SECRET', 'TOKEN', 'KEY']
    leaks = []
    for var in sensitive_vars:
        pattern = rf'{var}[\s:=]*([a-zA-Z0-9_\-]{10,})'
        matches = re.finditer(pattern, agent_output, re.IGNORECASE)
        for match in matches:
            if var in os.environ:
                leaks.append({
                    'variable': var,
                    'exposed_value': match.group(1),
                    'real_value_exists': bool(os.environ.get(var))
                })
    return leaks

import ast
import re

def audit_smolagents_code(code: str) -> dict:
    tree = ast.parse(code)
    issues = []

    # Check for print/debug statements with variables
    for node in ast.walk(tree):
        if isinstance(node, ast.Call):
            if isinstance(node.func, ast.Name) and node.func.id in ['print', 'log', 'debug']:
                issues.append(f'Dangerous {node.func.id} call at line {node.lineno}')

    # Check for file writes
    file_writes = re.findall(r'\.write\(|open\([^,]+,[\'"][wa]\)', code)
    if file_writes:
        issues.append(f'File write operations detected: {file_writes}')

    return {'issues': issues, 'severity': 'HIGH' if issues else 'CLEAR'}
